import json, random
random.seed(42)

entries = []
def T(code, test, lang):
    entries.append({"instruction": "Asagidaki fonksiyon icin unit test yaz:\n" + code, "response": test, "language": lang, "category": "test", "type": "manual", "format": "test"})

P="python";JS="javascript";JV="java";G="go"

def pyA(name, asserts):
    return f"def test_{name}():\n    " + "\n    ".join(asserts.split("\n")) + "\nimport pytest; pytest.main()"

def jsA(name, asserts):
    parts = [f"console.assert({p})" for p in asserts.split("\n")]
    return f"function test_{name}(){{\n  " + ";\n  ".join(parts) + ";\n}}test_{name}();"

def goA(name, asserts):
    return f"package main\nimport \"testing\"\nfunc Test{name}(t *testing.T) {{\n    " + "\n    ".join(asserts.split("\n")) + "\n}}"

def javaA(name, asserts):
    lines = [f"        {p};" for p in asserts.split("\n")]
    return f"import org.junit.*;\nimport static org.junit.Assert.*;\npublic class {name}Test {{\n    @Test\n    public void test{name}() {{\n" + "\n".join(lines) + "\n    }\n}}"

def add(name, code, asserts, lang, make):
    T(code, make(name, asserts), lang)

