("lru","class LRUCache:\n    def __init__(s,cap): s.cap=cap; s.cache={}; s.order=[]\n    def get(s,k):\n        if k in s.cache: s.order.remove(k); s.order.append(k); return s.cache[k]\n        return -1\n    def put(s,k,v):\n        if k in s.cache: s.order.remove(k)\n        elif len(s.cache)>=s.cap: o=s.order.pop(0); del s.cache[o]\n        s.cache[k]=v; s.order.append(k)","c=LRUCache(2)\nc.put(1,1);c.put(2,2)\nassert c.get(1)==1\nc.put(3,3); assert c.get(2)==-1\nc.put(4,4); assert c.get(1)==-1; assert c.get(3)==3"),
