("bal","function balParen(s){const st=[],p={\")\":\"(\",\"]\":\"[\",\"}\":\"{\"};for(const c of s){if(\"([{\".includes(c))st.push(c);else if(\")]}\".includes(c)){if(!st.length||st.pop()!==p[c])return false}}return st.length===0}","balParen(\"()[]{}\")===true\nbalParen(\"([)]\")===false"),
("fizz","function fizzbuzz(n){const r=[];for(let i=1;i<=n;i++){if(i%15===0)r.push(\"FizzBuzz\");else if(i%3===0)r.push(\"Fizz\");else if(i%5===0)r.push(\"Buzz\");else r.push(String(i))}return r}","JSON.stringify(fizzbuzz(5))===JSON.stringify([\"1\",\"2\",\"Fizz\",\"4\",\"Buzz\"])"),
