("wc","function wordCount(s){const m={};s.toLowerCase().match(/\\w+/g)?.forEach(w=>m[w]=(m[w]||0)+1);return m}","const r=wordCount(\"a b a\");r.a===2&&r.b===1"),
("roman","function toRoman(n){const v=[1000,900,500,400,100,90,50,40,10,9,5,4,1],s=[\"M\",\"CM\",\"D\",\"CD\",\"C\",\"XC\",\"L\",\"XL\",\"X\",\"IX\",\"V\",\"IV\",\"I\"];let r=\"\";for(let i=0;i<v.length;i++){while(n>=v[i]){r+=s[i];n-=v[i]}}return r}","toRoman(4)===\"IV\"\ntoRoman(1994)===\"MCMXCIV\""),
("fromroman","function fromRoman(s){const r={I:1,V:5,X:10,L:50,C:100,D:500,M:1000};let t=0;for(let i=0;i<s.length;i++){if(i+1<s.length&&r[s[i]]<r[s[i+1]])t-=r[s[i]];else t+=r[s[i]]}return t}","fromRoman(\"IV\")===4\nfromRoman(\"MCMXCIV\")===1994"),
("msort","function mSort(a){if(a.length<=1)return a;const m=Math.floor(a.length/2);return merge(mSort(a.slice(0,m)),mSort(a.slice(m)));function merge(l,r){const res=[];let i=0,j=0;while(i<l.length&&j<r.length){if(l[i]<=r[j])res.push(l[i++]);else res.push(r[j++])}return res.concat(l.slice(i)).concat(r.slice(j))}}","JSON.stringify(mSort([38,27,43,3,9,82,10]))===JSON.stringify([3,9,10,27,38,43,82])"),
("isort","function iSort(a){for(let i=1;i<a.length;i++){const k=a[i];let j=i-1;while(j>=0&&a[j]>k){a[j+1]=a[j];j--}a[j+1]=k}return a}","JSON.stringify(iSort([12,11,13,5,6]))===JSON.stringify([5,6,11,12,13])"),
("ssort","function sSort(a){for(let i=0;i<a.length;i++){let mi=i;for(let j=i+1;j<a.length;j++)if(a[j]<a[mi])mi=j;[a[i],a[mi]]=[a[mi],a[i]]}return a}","JSON.stringify(sSort([64,25,12,22,11]))===JSON.stringify([11,12,22,25,64])"),
("pal2","function palCheck(s){const c=s.replace(/[^a-z0-9]/gi,\"\").toLowerCase();return c===c.split(\"\").reverse().join(\"\")}","palCheck(\"A man, a plan, a canal: Panama\")===true\npalCheck(\"hello\")===false"),
("long_w","function longestWord(s){return s.split(/\\s+/).reduce((l,w)=>w.length>l.length?w:l,\"\")}","longestWord(\"merhaba dunya\")===\"merhaba\""),
