("lru2","function lruCache(cap){const m=new Map();return{get(k){if(!m.has(k))return-1;const v=m.get(k);m.delete(k);m.set(k,v);return v},put(k,v){if(m.has(k))m.delete(k);else if(m.size>=cap){const o=m.keys().next().value;m.delete(o)}m.set(k,v)}}}","const c=lruCache(2);c.put(1,1);c.put(2,2);c.put(3,3);c.get(1)===-1"),
