("Merge","public class ArrayUtils { public static int[] mergeSort(int[] a){if(a.length<=1)return a;int m=a.length/2;return merge(mergeSort(java.util.Arrays.copyOfRange(a,0,m)),mergeSort(java.util.Arrays.copyOfRange(a,m,a.length)));}private static int[] merge(int[] l,int[] r){int[] res=new int[l.length+r.length];int i=0,j=0,k=0;while(i<l.length&&j<r.length)res[k++]=l[i]<=r[j]?l[i++]:r[j++];while(i<l.length)res[k++]=l[i++];while(j<r.length)res[k++]=r[j++];return res;} }","assertArrayEquals(new int[]{3,9,10,27,38,43,82},ArrayUtils.mergeSort(new int[]{38,27,43,3,9,82,10}))"),
("BinSearch","public class ArrayUtils { public static int binSearch(int[] a,int t){int l=0,r=a.length-1;while(l<=r){int m=(l+r)/2;if(a[m]==t)return m;if(a[m]<t)l=m+1;else r=m-1;}return-1;} }","assertEquals(2,ArrayUtils.binSearch(new int[]{1,3,5,7,9},5))\nassertEquals(-1,ArrayUtils.binSearch(new int[]{1,3,5,7,9},2))"),
