("FromRoman","public class StringUtils { public static int fromRoman(String s){java.util.Map<Character,Integer> r=new java.util.HashMap<>();r.put(\'I\',1);r.put(\'V\',5);r.put(\'X\',10);r.put(\'L\',50);r.put(\'C\',100);r.put(\'D\',500);r.put(\'M\',1000);int t=0;for(int i=0;i<s.length();i++){if(i+1<s.length()&&r.get(s.charAt(i))<r.get(s.charAt(i+1)))t-=r.get(s.charAt(i));else t+=r.get(s.charAt(i));}return t;} }","assertEquals(4,StringUtils.fromRoman(\"IV\"))\nassertEquals(1994,StringUtils.fromRoman(\"MCMXCIV\"))"),
