("ValidTime","public class StringUtils { public static boolean validTime(String t){return t.matches(\"^([01]\\\\d|2[0-3]):[0-5]\\\\d(:[0-5]\\\\d)?$\");} }","assertTrue(StringUtils.validTime(\"14:30\"))\nassertFalse(StringUtils.validTime(\"25:00\"))"),
("CharCount","public class StringUtils { public static java.util.Map<Character,Integer> charCount(String s){java.util.Map<Character,Integer> m=new java.util.HashMap<>();for(char c:s.toCharArray())m.put(c,m.getOrDefault(c,0)+1);return m;} }","assertEquals(1,(int)StringUtils.charCount(\"hello\").get(\'h\'))\nassertEquals(2,(int)StringUtils.charCount(\"hello\").get(\'l\'))"),
("LongestW","public class StringUtils { public static String longestW(String t){String[] w=t.split(\" \");String r=\"\";for(String x:w)if(x.length()>r.length())r=x;return r;} }","assertEquals(\"merhaba\",StringUtils.longestW(\"merhaba dunya\"))"),
("ValidTC","public class IdentityUtils { public static boolean validTC(String tc){if(tc.length()!=11||!tc.matches(\"\\\\d+\"))return false;int[] d=tc.chars().map(c->c-\'0\').toArray();int o=0,e=0;for(int i=0;i<10;i+=2)o+=d[i];for(int i=1;i<9;i+=2)e+=d[i];if((o*7-e)%10!=d[9])return false;int s=0;for(int i=0;i<10;i++)s+=d[i];return s%10==d[10];} }","assertTrue(IdentityUtils.validTC(\"10000000146\"))\nassertFalse(IdentityUtils.validTC(\"12345678901\"))"),
("ValidIBAN","public class IdentityUtils { public static boolean validIBAN(String i){i=i.replace(\" \",\"\").toUpperCase();return i.startsWith(\"TR\")&&i.length()==26&&i.substring(2).matches(\"\\\\d+\");} }","assertTrue(IdentityUtils.validIBAN(\"TR330006100519786457841326\"))\nassertFalse(IdentityUtils.validIBAN(\"TR12\"))"),
("Clamp","public class MathUtils { public static int clamp(int n,int lo,int hi){return Math.max(lo,Math.min(n,hi));} }","assertEquals(5,MathUtils.clamp(5,1,10))\nassertEquals(1,MathUtils.clamp(-5,1,10))"),
("ToCamel","public class StringUtils { public static String toCamel(String s){String[] w=s.split(\"[-_\\\\s]\");StringBuilder r=new StringBuilder(w[0].toLowerCase());for(int i=1;i<w.length;i++){String x=w[i];r.append(Character.toUpperCase(x.charAt(0))).append(x.substring(1).toLowerCase());}return r.toString();} }","assertEquals(\"helloWorld\",StringUtils.toCamel(\"hello-world\"))"),
("ToSnake","public class StringUtils { public static String toSnake(String s){return s.replaceAll(\"([A-Z])\",\"_$1\").toLowerCase().replaceAll(\"^_\",\"\").replaceAll(\"[\\\\s-]\",\"_\");} }","assertEquals(\"hello_world\",StringUtils.toSnake(\"helloWorld\"))"),
("SortedArr","public class ArrayUtils { public static boolean isSorted(int[] a){return java.util.stream.IntStream.range(0,a.length-1).noneMatch(i->a[i]>a[i+1]);} }","assertTrue(ArrayUtils.isSorted(new int[]{1,2,3}))"),
("Queue","public class Queue{private java.util.LinkedList<Integer> items=new java.util.LinkedList<>();public void enq(int v){items.addLast(v);}public int deq(){return items.removeFirst();}public boolean empty(){return items.isEmpty();}public int front(){return items.getFirst();}}","Queue q=new Queue();q.enq(1);q.enq(2);assertEquals(1,q.deq());assertEquals(2,q.front())"),
("Stack","public class Stack{private java.util.LinkedList<Integer> items=new java.util.LinkedList<>();public void push(int v){items.addLast(v);}public int pop(){return items.removeLast();}public boolean empty(){return items.isEmpty();}public int peek(){return items.getLast();}}","Stack s=new Stack();assertTrue(s.empty());s.push(1);s.push(2);assertEquals(2,s.pop());assertEquals(1,s.peek())"),
("BinaryToDec","public class MathUtils { public static int binToDec(String b){return Integer.parseInt(b,2);} }","assertEquals(5,MathUtils.binToDec(\"101\"))\nassertEquals(0,MathUtils.binToDec(\"0\"))"),
