("LCM2","public class MathUtils { public static int lcm2(int a,int b){return a*b/gcd(a,b);}private static int gcd(int a,int b){while(b!=0){int t=b;b=a%b;a=t;}return a;} }","assertEquals(12,MathUtils.lcm2(4,6))"),
("Pangram","public class StringUtils { public static boolean isPangram(String s){return s.toLowerCase().chars().filter(Character::isLetter).distinct().count()==26;} }","assertTrue(StringUtils.isPangram(\"The quick brown fox jumps over the lazy dog\"))"),
("Memo","public class Memoize { public static java.util.function.Function<Integer,Integer> memoFib(){java.util.Map<Integer,Integer> c=new java.util.HashMap<>();return n->c.computeIfAbsent(n,x->x<=1?1:memoFib().apply(x-1)+memoFib().apply(x-2));} }","assertEquals(55,(int)Memoize.memoFib().apply(10))"),
("HashPW","public class CryptoUtils { public static String hashPW(String p)throws Exception{java.security.MessageDigest d=java.security.MessageDigest.getInstance(\"SHA-256\");byte[] h=d.digest(p.getBytes(\"UTF-8\"));StringBuilder sb=new StringBuilder();for(byte b:h)sb.append(String.format(\"%02x\",b));return sb.toString();} }","assertEquals(64,CryptoUtils.hashPW(\"test\").length())"),
("JSONValid","public class StringUtils { public static boolean isJSON(String s){try{new org.json.JSONObject(s);return true;}catch(Exception e){return false;}} }","assertTrue(StringUtils.isJSON(\'{\"a\":1}\'))"),
