("Stack","type Stack struct{ items []int }; func (s *Stack) Push(v int){ s.items=append(s.items,v) }; func (s *Stack) Pop() int { if len(s.items)==0 { panic(\"empty\") }; v:=s.items[len(s.items)-1]; s.items=s.items[:len(s.items)-1]; return v }; func (s *Stack) Empty() bool { return len(s.items)==0 }","s:=&Stack{}; if !s.Empty() { t.Fail() }; s.Push(1); s.Push(2); if s.Pop()!=2 { t.Fail() }"),
